RobotManager = {}
RobotManager.robotList = {}

function RobotManager:addRobot(robot)
    RobotManager.robotList[robot.entityId] = robot
end

function RobotManager:getRobot(entityId)
    return RobotManager.robotList[entityId]
end

function RobotManager:removeRobot(entityId)
    RobotManager.robotList[entityId] = nil
end

function RobotManager:onTick(ticks)
    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        vPlayer:checkRefreshRobot(ticks)
    end

    local count = 0
    for _, robot in pairs(self.robotList) do
        robot:onTick(ticks)
        count = count + 1
    end

    --print("RobotManager:onTick " .. count)
end

function RobotManager:refreshRobot(rakssid)
    local player = PlayerManager:getPlayerByRakssid(rakssid)
    if player == nil then
        return
    end

    if player.hasRobot then
        return
    end

    local config = RobotConfig:randRobot()
    if config == nil then
        return
    end

    local pos = VectorUtil.newVector3(0, 0, 0)
    local repeatCount = 0
    repeat
        pos = MathUtil:randomInCircle(player:getPosition(), config.refreshRadius)

        local ret, newPos = ToolUtil:getStandPos(pos)
        if ret then
            pos = newPos
            break
        end

        repeatCount = repeatCount + 1
    until(repeatCount >= Define.maxLoopCount)

    if repeatCount >= Define.maxLoopCount then
        HostApi.log("getStandPos failed!")
    end

    --HostApi.log(string.format("MathUtil:randomInCircle %d %d %d", pos.x, pos.y, pos.z))

    local entityId = EngineWorld:addRobot(pos, config.i_robotId, 0, config.s_actor)
    local robot = GameRobot.new(config, entityId, player.userId)
    RobotManager:addRobot(robot)

    player:onAddRobot(entityId)
end

return RobotManager